import React from "react";

export default function ResultCard({ priceRaw, livePriceData, isLiveLoading, liveError, rates = {}, currency = "USD", baseCurrency = "USD" }) {
  if (priceRaw == null) {
    return (
      <div className="bg-white dark:bg-gray-700 p-4 rounded shadow">
        <p className="text-sm text-gray-500 dark:text-gray-300">No prediction yet. Submit the form to see results.</p>
      </div>
    );
  }

  let converted = priceRaw;
  if (rates && rates[currency]) converted = priceRaw * rates[currency];

  const formatted = new Intl.NumberFormat(undefined, { style: "currency", currency }).format(converted);

  const low = converted * 0.85;
  const high = converted * 1.15;
  const formattedLow = new Intl.NumberFormat(undefined, { style: "currency", currency }).format(low);
  const formattedHigh = new Intl.NumberFormat(undefined, { style: "currency", currency }).format(high);

  let formattedLive = null;
  if (livePriceData && livePriceData.price) {
     let liveConv = livePriceData.price;
     // If Kayak returned USD, we need to convert it if the base is not USD.
     // But wait, our rates are based on INR. Kayak returns USD.
     // Let's assume the API returns USD, convert to INR first, then to selected currency.
     if (livePriceData.currency === "USD") {
        const usdToInr = (rates["INR"] / rates["USD"]) || 83; // fallback 83
        const inrPrice = livePriceData.price * usdToInr;
        liveConv = inrPrice * (rates[currency] || 1);
     } else {
        liveConv = livePriceData.price * (rates[currency] || 1);
     }
     formattedLive = new Intl.NumberFormat(undefined, { style: "currency", currency }).format(liveConv);
  }

  return (
    <div className="bg-white dark:bg-gray-700 p-4 rounded shadow">
      <div className="grid grid-cols-2 gap-4">
        {/* Predicted Price */}
        <div>
          <h3 className="text-lg font-semibold text-gray-800 dark:text-white">Predicted Price</h3>
          <div className="mt-2">
            <div className="text-3xl font-bold text-gray-900 dark:text-white">{formatted}</div>
            <div className="text-sm text-gray-500 dark:text-gray-300 mt-1">
              Range: {formattedLow} — {formattedHigh}
            </div>
            <div className="mt-4 text-xs text-gray-500 dark:text-gray-300">
              Confidence: Approx ±15% (model dependent)
            </div>
          </div>
        </div>

        {/* Live Price */}
        <div className="border-l pl-4 dark:border-gray-600">
          <h3 className="text-lg font-semibold text-blue-600 dark:text-blue-400">Actual Live Price</h3>
          <div className="mt-2">
            {isLiveLoading ? (
              <div className="animate-pulse flex space-x-4">
                <div className="h-8 bg-slate-200 dark:bg-slate-600 rounded w-3/4"></div>
              </div>
            ) : liveError ? (
              <span className="inline-flex items-center rounded-md bg-red-50 px-2 py-1 text-xs font-medium text-red-700 ring-1 ring-inset ring-red-600/10 dark:bg-red-900/20 dark:text-red-400">
                Unavailable (Rate Limited)
              </span>
            ) : livePriceData ? (
              <>
                <div className="text-3xl font-bold text-blue-600 dark:text-blue-400">{formattedLive}</div>
                <div className="text-sm text-gray-500 dark:text-gray-300 mt-1">
                  Found on Kayak API
                </div>
                {livePriceData.airline && (
                  <div className="mt-2 text-xs font-semibold bg-blue-100 dark:bg-blue-900 text-blue-800 dark:text-blue-200 inline-block px-2 py-1 rounded">
                    {livePriceData.airline}
                  </div>
                )}
              </>
            ) : (
              <div className="text-sm text-gray-500 dark:text-gray-400">Loading live data...</div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
